import React, { useState, useEffect, useMemo } from 'react';

const Icon = ({ name }) => {
  const icons = {
    telegram: (
      <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm4.64 6.8c-.15 1.58-.8 5.42-1.13 7.19-.14.75-.42 1-.68 1.03-.58.05-1.02-.38-1.58-.75-.88-.58-1.38-.94-2.23-1.5-.99-.65-.35-1.01.22-1.59.15-.15 2.71-2.48 2.76-2.69.01-.03.01-.14-.07-.2-.08-.06-.19-.04-.27-.02-.11.02-1.93 1.23-5.46 3.62-.51.35-.98.53-1.39.52-.46-.01-1.33-.26-1.98-.48-.8-.27-1.43-.42-1.37-.89.03-.25.38-.51 1.03-.78 4.04-1.76 6.74-2.92 8.09-3.48 3.85-1.6 4.64-1.88 5.17-1.89.11 0 .37.03.54.17.14.12.18.28.2.45-.02.07-.02.13-.03.19z"/>
    ),
    phone: (
      <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/>
    ),
    close: (
      <path d="M19 6.41L17.59 5 12 10.59 6.41 5 5 6.41 10.59 12 5 17.59 6.41 19 12 13.41 17.59 19 19 17.59 13.41 12z"/>
    )
  };

  return (
    <svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor">
      {icons[name]}
    </svg>
  );
};

const App = () => {
  const [filter, setFilter] = useState('Все');
  const [isScrolled, setIsScrolled] = useState(false);
  const [showArchive, setShowArchive] = useState(false);
  const [selectedProject, setSelectedProject] = useState(null);

  const categories = ['Все', 'Айдентика', 'Логотипы', 'Веб-дизайн', 'Печатная графика'];

  const projects = useMemo(() => ({
    featured: [
      { id: 'f1', title: "Проект айдентики", cat: "Айдентика", year: 2025, img: "https://images.unsplash.com/photo-1626785774573-4b799315345d?auto=format&fit=crop&q=80&w=800", pdf: "#", desc: "Подробное описание вашего проекта айдентики здесь." },
      { id: 'f2', title: "Веб-интерфейс", cat: "Веб-дизайн", year: 2025, img: "https://images.unsplash.com/photo-1551288049-bbbda5366392?auto=format&fit=crop&q=80&w=800", pdf: "#", desc: "Описание процесса создания веб-интерфейса." },
      { id: 'f3', title: "Логотип и стиль", cat: "Логотипы", year: 2025, img: "https://images.unsplash.com/photo-1572044162444-ad60f128bde2?auto=format&fit=crop&q=80&w=800", pdf: "#", desc: "Работа над логотипом и фирменным стилем." },
    ],
    archive: [
      { id: 'a1', title: "Учебный логотип", cat: "Логотипы", year: 2024, img: "https://images.unsplash.com/photo-1614850523296-d8c1af93d400?auto=format&fit=crop&q=80&w=800", pdf: "#", desc: "Архивная работа." },
    ]
  }), []);

  const filterFn = (p) => filter === 'Все' || p.cat === filter;
  const filteredFeatured = projects.featured.filter(filterFn);
  const filteredArchive = projects.archive.filter(filterFn);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollTo = (id) => {
    const el = document.getElementById(id);
    if (el) {
      window.scrollTo({ top: el.offsetTop - 140, behavior: 'smooth' });
    }
  };

  return (
    <div className="app-container">
      <div className="bg-glow"></div>
      <div className="bg-noise"></div>

      {/* ШАПКА КАК БЫЛА В ОРИГИНАЛЕ */}
      <div className="header-fixed-block">
        <header className={`header ${isScrolled ? 'header-shrink' : ''}`}>
          <div className="header-inner">
            <div className="logo">
              <span className="logo-dot"></span>
              АЛЕКСАНДРА БЛАГОДАТСКИХ
            </div>
            <nav className="desktop-nav">
              <button onClick={() => scrollTo('projects')}>Проекты</button>
              <button onClick={() => scrollTo('about')}>Обо мне</button>
              <button onClick={() => scrollTo('contact')}>Контакты</button>
            </nav>
            <div className="header-icons">
              <a href="https://t.me/renraie" target="_blank" rel="noreferrer" className="glass-icon"><Icon name="telegram"/></a>
              <a href="tel:+79639960003" className="glass-icon"><Icon name="phone"/></a>
            </div>
          </div>
        </header>

        <div className="filter-bar">
          <div className="filter-inner">
            {categories.map(cat => (
              <button 
                key={cat} 
                onClick={() => setFilter(cat)}
                className={`filter-tag ${filter === cat ? 'active' : ''}`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      <section id="about" className="hero-section">
        <h1 className="reveal-text">
          Учусь делать <span className="italic-accent">красивый</span> <br/>
          и <span className="outline-text">понятный</span> дизайн.
        </h1>
        <p className="fade-in-delay">
          Привет, я Александра. Помогаю брендам обрести своё лицо.
        </p>
      </section>

      <main id="projects" className="projects-section">
        <div className="section-header">
           <h2 className="section-title">Избранные проекты</h2>
           <div className="section-line"></div>
        </div>

        <div className="projects-grid">
          {filteredFeatured.map((project, index) => (
            <div key={project.id} className="project-card" onClick={() => setSelectedProject(project)} style={{ animationDelay: `${index * 0.1}s` }}>
              <div className="img-container">
                <img src={project.img} alt={project.title} />
                <div className="img-overlay">
                   <span>Смотреть кейс</span>
                </div>
              </div>
              <div className="project-details">
                <div className="project-info-main">
                  <span className="category-tag">{project.cat}</span>
                  <h3>{project.title}</h3>
                </div>
                <span className="year">{project.year}</span>
              </div>
            </div>
          ))}
        </div>

        <div className="archive-wrapper">
          <button onClick={() => setShowArchive(!showArchive)} className="archive-toggle-btn">
            <span className="btn-text">{showArchive ? 'Скрыть архив' : 'Архив работ'}</span>
            <span className="btn-icon">{showArchive ? '↑' : '↓'}</span>
          </button>

          {showArchive && (
            <div className="archive-grid">
              {filteredArchive.map((project) => (
                <div key={project.id} className="archive-item" onClick={() => setSelectedProject(project)}>
                  <div className="archive-img-box">
                      <img src={project.img} alt={project.title} />
                  </div>
                  <div className="archive-info">
                    <h4>{project.title}</h4>
                    <p>{project.cat}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      {/* МОДАЛЬНОЕ ОКНО */}
      {selectedProject && (
        <div className="project-overlay" onClick={() => setSelectedProject(null)}>
          <div className="project-modal" onClick={e => e.stopPropagation()}>
            <button className="close-modal" onClick={() => setSelectedProject(null)}>
              <Icon name="close" />
            </button>
            <div className="modal-body">
              <div className="modal-info">
                <span className="category-tag">{selectedProject.cat}</span>
                <h2>{selectedProject.title}</h2>
                <p>{selectedProject.desc}</p>
                <div className="modal-year">Год: {selectedProject.year}</div>
              </div>
              <div className="modal-content">
                {selectedProject.pdf !== "#" ? (
                  <iframe src={selectedProject.pdf} title="PDF Viewer" width="100%" height="100%" />
                ) : (
                  <div className="pdf-placeholder">
                    <img src={selectedProject.img} alt="preview" />
                    <p>Презентация в разработке</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      <footer id="contact" className="main-footer">
        <div className="footer-container">
          <div className="footer-content">
            <span className="footer-label">Давайте работать вместе</span>
            <h2 className="footer-heading">Связаться со мной</h2>
            <div className="footer-links">
              <a href="tel:+79639960003" className="big-link"><span className="link-arrow">↗</span> 8 (963) 996-00-03</a>
              <a href="https://t.me/renraie" target="_blank" rel="noreferrer" className="big-link"><span className="link-arrow">↗</span> Telegram: @renraie</a>
            </div>
          </div>
          <div className="footer-bottom">
            <p className="copyright">© 2024—2026 Alexandra Blagodatskikh</p>
          </div>
        </div>
      </footer>

      <style>{`
