        .project-card:nth-child(even) { transform: translateY(60px); }
        .img-container { position: relative; border-radius: 32px; overflow: hidden; aspect-ratio: 16/11; border: 1px solid var(--glass-border); transition: 0.8s cubic-bezier(0.16, 1, 0.3, 1); }
        .img-container img { width: 100%; height: 100%; object-fit: cover; transition: 1.2s; filter: saturate(0.8); }
        .img-overlay { position: absolute; inset: 0; background: rgba(0,0,0,0.4); display: flex; align-items: center; justify-content: center; opacity: 0; transition: 0.4s; backdrop-filter: blur(4px); }
        .img-overlay span { padding: 12px 24px; border-radius: 30px; background: #fff; color: #000; font-size: 12px; font-weight: 600; }
        .project-card:hover .img-overlay { opacity: 1; }
        .project-card:hover img { transform: scale(1.1); }
        .project-details { display: flex; justify-content: space-between; align-items: flex-start; padding: 25px 10px 0; }
        .project-details h3 { margin: 0; font-size: 28px; font-family: 'Playfair Display', serif; font-weight: 400; }
        .category-tag { font-size: 10px; text-transform: uppercase; color: var(--accent); letter-spacing: 0.1em; display: block; margin-bottom: 8px; }

        /* MODAL STYLES */
        .project-overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.9); z-index: 2000; display: flex; align-items: center; justify-content: center; padding: 40px; backdrop-filter: blur(10px); }
        .project-modal { background: #0b0b0d; width: 100%; max-width: 1100px; height: 85vh; border-radius: 32px; position: relative; border: 1px solid var(--glass-border); overflow: hidden; }
        .close-modal { position: absolute; top: 20px; right: 20px; background: #fff; color: #000; border: none; width: 40px; height: 40px; border-radius: 50%; cursor: pointer; z-index: 10; display: flex; align-items: center; justify-content: center; }
        .modal-body { display: grid; grid-template-columns: 350px 1fr; height: 100%; }
        .modal-info { padding: 60px 40px; border-right: 1px solid var(--glass-border); overflow-y: auto; }
        .modal-info h2 { font-family: 'Playfair Display', serif; font-size: 32px; margin: 20px 0; }
        .modal-info p { color: var(--text-dim); line-height: 1.6; font-size: 15px; }
        .modal-content { background: #111; }
        .pdf-placeholder { height: 100%; display: flex; flex-direction: column; align-items: center; justify-content: center; }
        .pdf-placeholder img { width: 70%; border-radius: 12px; opacity: 0.4; margin-bottom: 20px; }

        /* ARCHIVE & FOOTER */
        .archive-wrapper { text-align: center; margin-top: 150px; }
        .archive-toggle-btn { padding: 20px 40px; border-radius: 20px; background: var(--glass); border: 1px solid var(--glass-border); color: #fff; cursor: pointer; }
        .archive-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 30px; margin-top: 60px; }
        .archive-item { background: var(--glass); padding: 15px; border-radius: 24px; text-align: left; cursor: pointer; }
        .main-footer { background: #050507; padding: 150px 0 60px; border-top: 1px solid var(--glass-border); }
        .footer-container { max-width: 1200px; margin: 0 auto; padding: 0 50px; }
        .big-link { font-size: clamp(24px, 4vw, 42px); color: #fff; text-decoration: none; display: block; margin-bottom: 20px; transition: 0.4s; }
        .big-link:hover { color: var(--accent); padding-left: 10px; }

        @keyframes fadeInUp { from { opacity: 0; transform: translateY(40px); } to { opacity: 1; transform: translateY(0); } }
        @media (max-width: 900px) {
          .projects-grid { grid-template-columns: 1fr; }
          .modal-body { grid-template-columns: 1fr; }
          .modal-info { height: auto; }
          .project-modal { height: 90vh; }
        }
      `}</style>
    </div>
